20	    input  to_vector               instr_in   ,
21	    output logic                   pop_instr  ,
22	    //Instruction Out
23	    output logic                   valid_o    ,
24	    output remapped_v_instr        instr_out  ,
25	    input  logic                   ready_i    ,
26	    //Memory Instruction Out
27	    output logic                   m_valid_o  ,
28	    output memory_remapped_v_instr m_instr_out,
29	    input  logic                   m_ready_i
30	);
31	
32	    localparam int ELEM_ADDR_WIDTH = $clog2(VECTOR_LANES*32);
33	    localparam int REGISTER_BITS   = $clog2(VECTOR_REGISTERS);
34	
35	    logic [  VECTOR_REGISTERS-1:0][VECTOR_TICKET_BITS-1:0] last_producer      ;
36	    logic [     REGISTER_BITS-1:0]                         next_free_vreg     ;
37	    logic [     REGISTER_BITS-1:0]                         rdst_destination   ;
38	    logic [       REGISTER_BITS:0]                         vreg_hop           ;
39	    logic [     REGISTER_BITS-1:0]                         remapped_src1      ;
40	    logic [     REGISTER_BITS-1:0]                         remapped_src2      ;
41	    logic [VECTOR_TICKET_BITS-1:0]                         next_ticket        ;
42	    logic                                                  do_operation, do_remap, rdst_remapped;
43	    logic                                                  memory_instr       ;
44	    logic                                                  reconfig_instr     ;
45	    logic                                                  do_reconfigure     ;
46	    logic                                                  load_instr         ;
47	    logic                                                  toepl_instr        ;
48	    logic                                                  toepl_conf         ;
49	    logic                                                  last_producer_wr_en;
50	
51	    //Check for special types of instructions
52	    assign reconfig_instr = instr_in.reconfigure;                          // general reconfiguration instr
53	    assign memory_instr   = instr_in.fu === `MEM_FU;                       // memory instr
54	    assign toepl_conf     = instr_in.microop === 7'b1110011;               // toeplitz prefetcher configuration
55	    assign toepl_instr    = instr_in.microop === 7'b1010011 & ~toepl_conf; // toeplitz prefetcher instr
56	    assign load_instr     = instr_in.microop[`LD_BIT] & ~toepl_instr;      // load instr
57	    //Push Pop Signals
58	    assign valid_o      = valid_in & do_operation;
59	    assign do_operation = (memory_instr | reconfig_instr) ? (valid_in & ready_i & m_ready_i) : (valid_in & ready_i);
60	    assign pop_instr    = do_operation;
61	    assign m_valid_o    = valid_in & (memory_instr | reconfig_instr) & do_operation;
62	
63	    assign do_reconfigure = reconfig_instr & do_operation;
64	
65	    // Instr Out Generation
66	    assign instr_out.vl          = instr_in.vl;
67	    assign instr_out.maxvl       = instr_in.maxvl;
68	    assign instr_out.valid       = instr_in.valid;
69	    assign instr_out.use_mask    = instr_in.use_mask;
70	    assign instr_out.immediate   = instr_in.immediate;
71	    assign instr_out.fu          = instr_in.fu;
72	    assign instr_out.microop     = instr_in.microop;
73	    assign instr_out.ticket      = next_ticket;
74	    assign instr_out.data1       = instr_in.data1;
75	    assign instr_out.data2       = instr_in.data2;
76	    assign instr_out.src1_iszero = 1'b0;
77	    assign instr_out.src2_iszero = 1'b0;
78	    assign instr_out.dst_iszero  = memory_instr & ((~load_instr & ~toepl_instr) | toepl_conf); // store instructions and toepl reconfig
79	                                                                                               // do not write anything
80	    assign instr_out.reconfigure = instr_in.reconfigure;
81	    // Pick the correct destination vreg
82	    assign instr_out.dst         = rdst_remapped ? rdst_destination :
83	                                   do_remap      ? next_free_vreg   :
84	                                                   instr_in.dst;
85	
86	    // Pick the correct source vregs
87	    assign instr_out.src1 = (instr_in.src1 === instr_in.dst) ? instr_out.dst : remapped_src1;
88	    assign instr_out.src2 = (instr_in.src2 === instr_in.dst) ? instr_out.dst : remapped_src2;
89	    //Assign Locking Bits based on Instruction Type
90	    assign instr_out.lock = (memory_instr && !reconfig_instr && ~toepl_conf && toepl_instr) ? 2'b10 :
91	                            (memory_instr && !reconfig_instr && ~toepl_conf && load_instr ) ? 2'b11 :
92	                            (memory_instr && !reconfig_instr && ~toepl_conf && !load_instr) ? 2'b01 :
93	                                                                                              2'b00;
94		//Memory Instr Out Generation
95	    assign m_instr_out.valid            = instr_out.valid;
96	    assign m_instr_out.dst              = instr_out.dst;
97	    assign m_instr_out.src1             = instr_out.src1;
98	    assign m_instr_out.src2             = instr_out.src2;
99	    assign m_instr_out.data1            = instr_out.data1;
100	    assign m_instr_out.data2            = instr_out.data2;
101	    assign m_instr_out.ticket           = instr_out.ticket;
102	    assign m_instr_out.immediate        = instr_out.immediate;
103	    assign m_instr_out.microop          = instr_in.microop;
104	    assign m_instr_out.reconfigure      = instr_in.reconfigure;
105	    assign m_instr_out.vl               = instr_in.vl;
106	    assign m_instr_out.maxvl            = instr_in.maxvl;
107	    assign m_instr_out.last_ticket_src1 = (last_producer[instr_in.src1] === 0) ? instr_out.ticket : last_producer[instr_in.src1];
108	    assign m_instr_out.last_ticket_src2 = (last_producer[instr_in.src2] === 0) ? instr_out.ticket : last_producer[instr_in.src2];
109	
110	    // Do remap enablers
111	    assign do_remap = do_operation & ~rdst_remapped;
112	    always_ff @(posedge clk or negedge rst_n) begin : vregHOP
113	        if(~rst_n) begin
114	            vreg_hop <= 1;
115	        end else if (do_reconfigure) begin
116	            vreg_hop <= (instr_in.maxvl >> $clog2(VECTOR_LANES));
117	        end
118	    end
119	
120		// Next Free vreg (similar job as the FL)
121	    always_ff @(posedge clk or negedge rst_n) begin : FreeVreg
122	        if(~rst_n) begin
123	            next_free_vreg <= 'b0;
124	        end else begin
125	        	if (do_reconfigure) begin
126	        		next_free_vreg <= 'b0;
127	            end else if(do_remap) begin
128	                next_free_vreg <= next_free_vreg + vreg_hop;
129	            end
130	        end
131	    end
132	
133	    //Next Free Ticket
134	    always_ff @(posedge clk or negedge rst_n) begin : NextTicket
135	        if(!rst_n) begin
136	            next_ticket <= 1;
137	        end else begin
138	            if(do_reconfigure) begin
139	                next_ticket <= 1;
140	            end else if(do_operation) begin
141	                next_ticket <= next_ticket +1;
142	                if (&next_ticket) next_ticket <= 1;
143	            end
144	        end
145	    end
146	
147	    //RAT module - Keeps current Mappings
148	    vrat #(
149	        .TOTAL_ENTRIES(VECTOR_REGISTERS),
150	        .DATA_WIDTH   (REGISTER_BITS   )
151	    ) vrat (
152	        .clk        (clk               ),
153	        .rst_n      (rst_n             ),
154	        .reconfigure(do_reconfigure    ),
155	        //Write Port
156	        .write_addr (instr_in.dst      ),
157	        .write_data (next_free_vreg    ),
158	        .write_en   (do_remap          ),
159	        //Read Port #1
160	        .read_addr_1(instr_in.dst      ),
161	        .read_data_1(rdst_destination  ),
162	        .remapped_1 (rdst_remapped     ),
163	        //Read Port #2
164	        .read_addr_2(instr_in.src1     ),
165	        .read_data_2(remapped_src1     ),
166	        .remapped_2 (                  ),
167	        //Read Port #3
168	        .read_addr_3(instr_in.src2     ),
169	        .read_data_3(remapped_src2     ),
170	        .remapped_3 (                  ),
171	        //Mask Port (always v1)
172	        .mask_src   (instr_out.mask_src)
173	    );
174	
175	    // Last producer Tracker (used for mem ops, stores do not udpate it)
176	    assign last_producer_wr_en = do_operation & (~memory_instr | load_instr | toepl_instr);
177	    always_ff @(posedge clk or negedge rst_n) begin
178	        if(~rst_n) begin
179	            last_producer <= '0;
180	        end else if(last_producer_wr_en) begin
181	            last_producer[instr_in.dst] <= next_ticket;
182	        end
183	    end
184	
185	    assign is_idle_o = ~valid_in;
186	
187	    //=======================================================
188		// Tracking for Debugging Purposes
189	    //=======================================================
190	    logic [VECTOR_REGISTERS:0] current_remaps, max_remaps;
191	    always_ff @(posedge clk or negedge rst_n) begin : tracking_current_remaps
192	        if(~rst_n) begin
193	            current_remaps <= 0;
194	        end else begin
195	            if(do_reconfigure) begin
196	                current_remaps <= 0;
197	            end else if(do_remap) begin
198	                current_remaps <= current_remaps + 1;
199	            end
200	        end
201	    end
202	
203	    always_ff @(posedge clk or negedge rst_n) begin : tracking_max_remaps
204	        if(~rst_n) begin
205	            max_remaps <= VECTOR_REGISTERS;
206	        end else begin
207	            if(do_reconfigure) begin
208	                max_remaps <= VECTOR_REGISTERS / (instr_in.maxvl >> $clog2(VECTOR_LANES));
209	            end
210	        end
211	    end
212	
213	
